templates.readBinding:
// Component
private readonly svc = inject(PatientDataService);
readonly {entity} = signal<{TypeFromGenerated} | null>(null);
readonly loading = signal(true);

async ngOnInit(): Promise<void> {
  try {
    const data = await this.svc.{getMethod}({...variables});
    this.{entity}.set(data.{dataPath});
  } finally {
    this.loading.set(false);
  }
}

templates.writeBinding:
// Component
async on{Action}(payload: {PayloadType}): Promise<void> {
  const optimistic = this.{entity}();
  // 1. Optimistic write (per event-mutation pattern)
  this.{entity}.update(prev => /* compute optimistic state */);
  try {
    // 2. Service call (tier 3)
    await this.svc.{mutationMethod}(payload);
    // 3. Reconcile — re-read or trust optimistic
    await this.refresh{Entity}();
  } catch (err) {
    // 4. Roll back
    this.{entity}.set(optimistic);
    this.errorService.surface(err);
  }
}
